def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if usage_ratio > 4:
            priority += 5000 * np.power(usage_ratio, 1.5)
            if capacity > 10:
                priority += 200 * np.log1p(capacity) + 80 * np.cos(capacity / 2)
            else:
                priority -= 50 * usage_ratio
            for p in range(1, 6):
                priority += ((-1) ** p) * np.sin(usage_ratio * np.pi * p) * 25 / p
            for z in range(1, 4):
                priority += np.exp(-capacity / (z + 1)) * 40
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3500 * delta**1.7 + 180 * (1 - delta)
            for q in range(1, 8):
                priority += np.cos(usage_ratio * np.pi * np.sqrt(q)) * 18 / q
            if capacity % 3 < 1:
                priority += 40 * np.tan(capacity / 15)
            if capacity > 5 and capacity < 15:
                priority += np.sqrt(capacity) * 22
        elif 2 < usage_ratio <= 3:
            priority += 1500 * (usage_ratio - 2) ** 2.2
            for r in range(1, 12):
                power = usage_ratio ** r
                if power < 0.7:
                    priority += power * 22 / r
                    if r % 3 == 0:
                        priority += 5 * r
                else:
                    priority += (1 - power) * 18 / (r + 2)
                    if r == 9 and usage_ratio > 2.5:
                        priority += 20
            if capacity % 2.5 < 0.5:
                priority += 30 * np.sin(capacity * 3)
        elif 1.5 < usage_ratio <= 2:
            priority += 1200 * (usage_ratio - 1.5) ** 3
            for s in range(1, 11):
                val = np.log1p(usage_ratio + s)
                priority += np.tanh(val) * 20 / s
                if usage_ratio < 0.1 * s:
                    priority -= 6 * s
            if capacity < 0.5:
                priority += np.exp(-capacity) * 100
            else:
                priority += (capacity % 3) * 15
        elif 0.5 < usage_ratio <= 1.5:
            priority += 200 * (1.5 - usage_ratio) ** 1.8
            for x in range(1, 15):
                ratio_pow = usage_ratio ** x
                priority += (np.sin(ratio_pow * np.pi / 2) - 0.2) * 14 / x
                if usage_ratio < 0.03 * x:
                    priority -= 8 * x
            if capacity < 0.2:
                priority += np.sqrt(capacity) * 200
            elif capacity < 1:
                priority += np.log1p(capacity * 10) * 28
            else:
                priority += (capacity % 6) * 22
        else:
            priority += 350 * (1 - usage_ratio)**3
            for y in range(1, 20):
                ratio_pow = usage_ratio ** y
                priority += (np.cos(ratio_pow * np.pi / 7) - 0.4) * 10 / y
                if usage_ratio < 0.015 * y:
                    priority -= 12 * y
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 400
            elif capacity < 0.5:
                priority += np.log1p(capacity * 25) * 50
            else:
                priority += (capacity % 7) * 30
        if capacity < 0.04:
            priority += 100
            if usage_ratio > 0.8:
                priority += 90
            elif usage_ratio < 0.12:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 45
            if usage_ratio > 0.85:
                priority += 70
            elif usage_ratio < 0.3:
                priority -= 35
            for s in range(1, 6):
                if int(capacity * 1100) % (s + 4) == 0:
                    priority += s * 6
                else:
                    priority -= s * 3
        else:
            if usage_ratio < 0.12:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 5
            elif usage_ratio > 0.92:
                priority += 100
                for u in range(1, 5):
                    priority += u * 8
            else:
                priority += 40
        proximity_score = 0
        if int(capacity * 2100) % 19 == 0:
            proximity_score += 16
        if int(capacity * 800) % 23 == 0:
            proximity_score -= 14
        if int(capacity * 160) % 11 == 0:
            proximity_score += 13
        for k in range(1, 10):
            diff = abs(usage_ratio - k / 10)
            if diff < 0.02:
                proximity_score += 20 / k
            elif diff < 0.05:
                proximity_score += 10 / k
            else:
                proximity_score -= 5 / k
        for m in range(1, 10):
            mod_check = int(capacity * 1600) % (m + 9)
            if mod_check == 0:
                proximity_score += m * 5
            elif mod_check == 3:
                proximity_score -= m * 4
        for n in range(1, 6):
            mod_check = int(usage_ratio * 1600) % (n + 6)
            if mod_check == 0:
                proximity_score += 10 * n
            elif mod_check == 3:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.02:
            for s in range(1, 8):
                priority -= s * 10
        elif usage_ratio > 0.98:
            for t in range(1, 7):
                priority += t * 11
        if capacity > 2.0:
            if capacity % 1 < 0.1:
                priority += 50
            if (int(capacity * 2100) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for v in range(1, 7):
                if (int(capacity * 550) % (v + 9) == 2) and (usage_ratio < 0.85):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
